import sys

class Solution:
    def minimumTime(self, n, relations, time):
        preds = [[] for _ in range(n + 1)]
        for u, v in relations:
            preds[v].append(u)
        sys.setrecursionlimit(100000)
        memo = {}

        def finish(u):
            if u in memo:
                return memo[u]
            best_prereq = 0
            for p in preds[u]:
                best_prereq = max(best_prereq, finish(p))
            result = best_prereq + time[u - 1]
            memo[u] = result
            return result

        return max(finish(u) for u in range(1, n + 1))

