from collections import deque

class Solution:
    def minimumTime(self, n, relations, time):
        indeg = [0] * (n + 1)
        adj = [[] for _ in range(n + 1)]
        for u, v in relations:
            adj[u].append(v)
            indeg[v] += 1
        finish = [0] * (n + 1)
        q = deque()
        for i in range(1, n + 1):
            if indeg[i] == 0:
                q.append(i)
                finish[i] = time[i - 1]
        while q:
            u = q.popleft()
            for v in adj[u]:
                if finish[u] + time[v - 1] > finish[v]:
                    finish[v] = finish[u] + time[v - 1]
                indeg[v] -= 1
                if indeg[v] == 0:
                    q.append(v)
        return max(finish[1:])

