var minimumTime = function(n, relations, time) {
    const indeg = new Array(n + 1).fill(0);
    const adj = Array.from({length: n + 1}, () => []);
    for (const [u, v] of relations) {
        adj[u].push(v);
        indeg[v]++;
    }
    const finish = new Array(n + 1).fill(0);
    const queue = [];
    for (let i = 1; i <= n; i++) {
        if (indeg[i] === 0) {
            queue.push(i);
            finish[i] = time[i - 1];
        }
    }
    let head = 0;
    while (head < queue.length) {
        const u = queue[head++];
        for (const v of adj[u]) {
            if (finish[u] + time[v - 1] > finish[v]) {
                finish[v] = finish[u] + time[v - 1];
            }
            indeg[v]--;
            if (indeg[v] === 0) queue.push(v);
        }
    }
    return Math.max(...finish.slice(1));
};
